    "history_rename_btn": "Rename hoc subsidia prō easier identification.",
    "history_save_unit_btn": "Servā mūtātiōnēs ad hoc unit's name et organization.",
    "history_unit_name_input": "Inscrībe name prō hoc unit (e.g., 'Week 3 - Ecosystems').",
    "persona_close": "Claude persona configuration pannus et return ad main interfaciēs.",
    "socratic_auto_read": "Mūtā automaticus textus-ad-speech reading Socratic discussion monita et responses.",
    "socratic_auto_send": "Permitte automaticus sending Socratic monita at timed intervals prō guided discussion.",
