    "socratic_expand": "Expand Socratic discussion pannus ad full aspice prō deeper engagement.",
    "wizard_back_results_btn": "Return ad quaere effectus ad ēlige different norma.",
    "wizard_close_btn": "Claude setup magus. tuus prōgressus est servātum et tu potest resume later.",
    "wizard_complete_btn": "Complē magus et generā tuus lectiō cum omnia configured cōnstitūtiōnēs applied.",
    "wizard_content_next_btn": "Proceed ad proximus contentum creation gradus in magus.",
    "wizard_find_standard_btn": "Quaere prō educational norma illud match tuus contentum thema.",
    "wizard_grade_option": "Ēlige hoc gradus classis prō tuus lectiō. Determines vocābulārium et conceptus complexitās.",
    "wizard_growth_goal_input": "Inscrībe learning growth fīnis prō discipulus ad achieve cum hoc contentum.",
    "wizard_instructions_input": "Adde accommodātus īnstrūctiō prō AI ad follow cum generandō lectiō contentum.",
    "wizard_interest_add_btn": "Adde discipulus interest thema ad personalize generātum contentum.",
    "wizard_interest_remove_btn": "Remove hoc interest thema ā personalization index.",
    "wizard_lang_add_btn": "Adde another lingua prō multilingual contentum generātiō.",
    "wizard_lang_remove_btn": "Remove hoc lingua ā trānslātiō index.",
