      "all_or_none_electrical_signal_sodium_i": "Signum electricum totum aut nihil. Natrium intus → depolarizat → kalium foras → repolarizat. ~1 ms. Celeritas propagationis: ~1 m/s (non myelinatum) ad ~100 m/s (myelinatum).",
      "fatty_insulation_made_by_glia_oligoden": "Isolatio adiposa a glia facta (oligodendrocytae in CNS, cellulae Schwann in PNS). Conductionem accelerat. In MS destructa.",
      "junction_between_neurons_electrical_or": "Iunctura inter neurones. Electrica aut chemica (pleraeque). Spatium ~0,02 µm.",
      "chemical_messengers_across_synapse_exc": "Nuntii chemici per synapsim. Excitatorii (glutamatum), inhibitorii (GABA), modulatorii (serotoninum, dopaminum).",
      "reward_motivation_motor_control_low_in": "Praemium, motivatio, moderatio motoria. Humile in Parkinsone; deregulatum in schizophrenia.",
      "mood_sleep_appetite_ssris_target_reupt": "Affectus, somnus, appetitus. ISRS recaptationem scopant.",
      "neuromuscular_junction_memory_attentio": "Iunctura neuromuscularis. Memoria + attentio. Humile in Alzheimero.",
      "astrocytes_support_bbb_oligodendrocyte": "Astrocytae (fulcrum, BBB), oligodendrocytae (myelinum in CNS), microglia (immunitas), cellulae ependymales (LCR).",
      "cerebrum_cortex_thinking_perception_ce": "Cerebrum (cortex — cogitatio, perceptio), cerebellum (coordinatio motoria), truncus cerebri (autonomicus), systema limbicum (affectus + memoria).",
      "brain_reorganizes_itself_strongest_in_": "Cerebrum se ipsum reordinat — fortissimum in pueritia sed continuum per totam vitam. Fundamentum discendi.",
      "tight_junctions_between_brain_capillar": "Iuncturae artae inter cellulas capillarium cerebri pleraque moleculas foris tenent. Provocatio maior pro traditione medicamentorum ad CNS.",
      "20_of_body_s_energy_at_rest_despite_be": "~20% energiae corporis in quiete quamvis ~2% massae sit. Praesertim pompae Na+/K+ gradientes ionicos manentes.",
      "first_mass_produced_human_protein_made": "Primum proteinum humanum massive productum. In E. coli (1982) factum. Insulinum suillum + bovinum substituit.",
      "single_target_therapies_humira_autoimm": "Therapiae scopi unici. Humira (autoimmune), Herceptin (carcinoma mammae HER2+), Keytruda (immunotherapia).",
      "covid_19_vaccines_pfizer_moderna_self_": "Vaccina contra COVID-19 (Pfizer, Moderna). Versiones autoamplificantes + applicationes non-COVID in progressu.",
      "replace_defective_genes_luxturna_inher": "Genes defectivos substituunt. Luxturna (caecitas hereditaria, FDA 2017). Zolgensma (SMA, 2019).",
      "engineered_immune_cells_yescarta_kymri": "Cellulae immunes ingeritae. Yescarta + Kymriah pro carcinomatis sanguinis. ~400.000 $ per dosim.",
      "bone_marrow_transplants_standard_for_d": "Transplantationes medullae ossium per decennia norma sunt. Accessus recentiores cum iPSC + ESC in probationibus.",
      "print_tissue_with_living_cells_scaffol": "Textum cum cellulis vivis + scaffoldis imprimit. Cutis, cartilago, vesica. Organa integra adhuc remota.",
      "engineer_biological_systems_bacteria_t": "Systemata biologica ingerit. Bacteria quae medicamenta producunt, saccharomyces qui opioida coquunt, biocombustibilia algarum.",
      "bt_corn_insect_resistance_roundup_read": "Maizium Bt (resistentia insectis), Roundup Ready (herbicidum), Oryza Aurea (vitaminum A).",
      "str_profiling_mtdna_degraded_samples_y": "Profilatio STR, mtDNA (specimina degradata), chromosoma Y (linea paterna). Comparatio in datorum basibus.",
      "snp_arrays_23andme_ancestrydna_reveals": "Dispositiones SNP (23andMe, AncestryDNA). Originem biogeographicam + cognatos per DNA revelant.",
      "detect_cancer_dna_in_blood_earlier_dia": "DNA carcinomatis in sanguine detegunt. Diagnosis maturior, curationis monitoratio.",
      "treat_solid_tumors_til_therapy_iovance": "Tumores solidos curant. Therapia TIL (Iovance, melanoma) a FDA anno 2024 approbata.",
      "engineered_microbes_clean_up_oil_spill": "Microbi ingeriti effusiones olei, pollutionem plasticam, metalla gravia purgant.",
